INSERT INTO agewell_responses (submitted_at, channel, practice_canonical, branch_site, practice_label_freeform, support_worker_rating, equipment_provided, signposted, online_meeting_concerns_discussed, medicine_review_beneficial, listened_to_concerns, more_independent, most_significant_difference, overall_rating, would_recommend, suggestions_concerns, completed_with_support, call_duration_seconds, transcript_json, user_agent) VALUES
('2026-05-05 14:23:00+00','web','Redwell Medical Centre',NULL,NULL,5,'yes','no','not_applicable','not_applicable','agree','agree','The lifeline button has given me back my confidence. After my fall in February I was terrified to be alone, and now I know help is just a press away.',5,'yes',NULL,'on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-05-02 10:15:00+00','telephony','Albany House Medical Centre',NULL,NULL,5,'yes','no','not_applicable','not_applicable','agree','agree','Sarah arranged the perching stool for me so I can prepare meals sitting down. Small thing but it has changed my days.',5,'yes',NULL,'phone_with_automated_assistant',387,'[{"role":"agent","message":"Hello, and thank you for calling the Ageing Well feedback line. I am an automated assistant — I would love about five to seven minutes of your time. Is now a good time?","time_offset_s":0},{"role":"caller","message":"Yes dear, that is fine.","time_offset_s":12},{"role":"agent","message":"Lovely. May I ask which GP practice you are registered with?","time_offset_s":15},{"role":"caller","message":"Albany House.","time_offset_s":19},{"role":"agent","message":"Thank you. On a scale from one to five, how would you rate the service from your Ageing Well support worker?","time_offset_s":22},{"role":"caller","message":"Oh, five out of five. Sarah was wonderful.","time_offset_s":28},{"role":"agent","message":"Five out of five, thank you.","time_offset_s":32}]'::jsonb,'DEMO_DATA_v1'),
('2026-04-30 16:42:00+00','web','Summerlee Medical Centre',NULL,NULL,4,'no','yes','not_applicable','not_applicable','agree','agree','Being put in touch with Age UK has helped me get out of the house once a week. The volunteer driver is lovely and we have a proper chat on the way.',4,'yes','Maybe quicker initial contact — I waited about three weeks for the first visit.','on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-27 11:08:00+00','paper','Irchester Health Centre',NULL,NULL,5,'no','yes','not_applicable','not_applicable','agree','agree','After my husband passed away in November I was struggling to manage the house. The team helped me work out what I could keep doing myself and what I needed help with. I feel I have a future again.',5,'yes',NULL,'with_support_worker',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-25 09:34:00+00','web','Abbey Medical Practice',NULL,NULL,3,'yes','no','not_applicable','not_applicable','neutral','neutral','Mixed feelings really. The first worker was excellent but then she left and the next one did not really know my situation. Had to start over.',3,'unsure','Better continuity would help — having to explain everything twice was tiring.','on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-23 15:21:00+00','telephony','Queensway Surgery',NULL,NULL,5,'yes','yes','not_applicable','not_applicable','agree','agree','The falls assessment showed I needed grab rails in the bathroom and a different mat by the back door. Both got sorted within two weeks.',4,'yes','All good thank you.','phone_with_automated_assistant',412,'[]'::jsonb,'DEMO_DATA_v1'),
('2026-04-21 13:47:00+00','web','Wollaston Surgery',NULL,NULL,4,'no','no','yes','yes','agree','agree','The medicine review was eye-opening — I was on a tablet I did not need any more, and one was making me dizzy. I feel sharper since they sorted it.',5,'yes',NULL,'on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-20 10:55:00+00','web','Redwell Medical Centre',NULL,NULL,5,'no','yes','not_applicable','not_applicable','agree','agree','Get up and Go classes have been brilliant. I have made friends and I am steadier on my feet.',5,'yes',NULL,'on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-18 16:12:00+00','paper','Albany House Medical Centre',NULL,NULL,2,'yes','no','not_applicable','not_applicable','disagree','neutral','Honestly it took weeks to get any real help and when it came it was not quite what we needed. My daughter ended up sorting most of it herself.',2,'no','Be honest about waiting times. We were told a few days and it was nearly a month.','with_support_worker',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-17 14:38:00+00','web','Summerlee Medical Centre',NULL,NULL,5,'yes','yes','not_applicable','not_applicable','agree','agree','My memory has been getting worse and the team have been so patient. They explained things slowly and gave me written notes I can refer back to.',5,'yes',NULL,'with_support_worker',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-16 11:24:00+00','telephony','Brackley Medical Centre',NULL,NULL,4,'no','yes','not_applicable','not_applicable','agree','agree','Being signposted to a befriender has been the best thing. I look forward to her visits.',4,'yes','Maybe a follow-up call after a month would be nice, just to check things are still going well.','phone_with_automated_assistant',298,'[]'::jsonb,'DEMO_DATA_v1'),
('2026-04-14 09:51:00+00','web','The Parks Medical Practice','Blisworth',NULL,5,'yes','no','not_applicable','not_applicable','agree','agree','The lifeline pendant and the key safe together mean my children can stop worrying about me. I am 84 and I am still in my own home.',5,'yes',NULL,'on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-13 15:07:00+00','web','Towcester Medical Centre',NULL,NULL,4,'no','yes','not_applicable','not_applicable','agree','agree','The social prescriber linked me with the gardening group at the community centre. Getting out twice a week makes such a difference.',5,'yes',NULL,'on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-12 13:32:00+00','telephony','Bugbrooke Medical Practice',NULL,NULL,3,'yes','no','not_applicable','not_applicable','neutral','neutral','It was alright. Not life-changing but I got a couple of useful pieces of equipment.',3,'unsure','Maybe more information at the start about what the service can and cannot do.','phone_with_automated_assistant',245,'[]'::jsonb,'DEMO_DATA_v1'),
('2026-04-11 10:45:00+00','web','Redwell Medical Centre',NULL,NULL,5,'yes','no','not_applicable','not_applicable','agree','agree','Completed on behalf of my mum — they helped her get a stair lift assessment which has meant she can stay in her own home. We cannot thank them enough.',5,'yes',NULL,'with_support_worker',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-10 14:19:00+00','web','Eleanor Cross Healthcare',NULL,NULL,5,'yes','no','yes','yes','agree','agree','After my hospital stay I was worried about coping at home. The Ageing Well team came round within 48 hours and made sure I had everything I needed.',5,'yes',NULL,'on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-09 11:36:00+00','paper','Danes Camp Medical Centre',NULL,NULL,4,'yes','yes','not_applicable','not_applicable','agree','agree','Got me a proper walking frame and pointed me towards the lunch club at the church.',4,'yes',NULL,'with_support_worker',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-08 16:54:00+00','web','Abbey Medical Practice',NULL,NULL,1,'no','no','not_applicable','not_applicable','disagree','disagree','Not much honestly. The visit felt rushed and I did not feel listened to.',1,'no','Take more time. Twenty minutes is not enough to understand what someone really needs.','on_my_own',NULL,NULL,'DEMO_DATA_v1'),
('2026-04-08 09:12:00+00','telephony','Wollaston Surgery',NULL,NULL,5,'no','yes','not_applicable','not_applicable','agree','agree','Margaret who came to see me was an absolute angel. She listened, she did not rush, she made me feel like a person not a problem.',5,'yes','Just please keep doing what you are doing.','phone_with_automated_assistant',356,'[{"role":"agent","message":"Hello, and thank you for calling the Ageing Well feedback line. I am an automated assistant — I would love about five to seven minutes of your time. Is now a good time?","time_offset_s":0},{"role":"caller","message":"Yes love, I have been meaning to ring.","time_offset_s":11},{"role":"agent","message":"Lovely. May I ask which GP practice you are registered with?","time_offset_s":15},{"role":"caller","message":"Wollaston.","time_offset_s":19},{"role":"agent","message":"Thank you. On a scale from one to five, how would you rate the service from your Ageing Well support worker?","time_offset_s":22},{"role":"caller","message":"Oh, five. Margaret was an absolute angel.","time_offset_s":29},{"role":"agent","message":"Five out of five, thank you. Did your support worker help you to get any specialist equipment, like a lifeline button or mobility aids?","time_offset_s":33},{"role":"caller","message":"No, no equipment, but she put me in touch with the lunch club which has been wonderful.","time_offset_s":42}]'::jsonb,'DEMO_DATA_v1'),
('2026-04-07 14:28:00+00','web','The Meadows Surgery, Thrapston',NULL,NULL,5,'yes','no','not_applicable','not_applicable','agree','agree','I did not know services like this even existed. They got me a personal alarm and a fall alarm and I sleep better at night knowing they are there.',5,'yes',NULL,'on_my_own',NULL,NULL,'DEMO_DATA_v1');